+// A pipe query starts with a standalone FROM. Marking it separately lets the
+// grammar distinguish it from a traditional FROM clause without changing how
+// traditional queries are parsed.
+function detectPipeFrom(tokens: Token[]): Token[] {
+  let atStatementStart = true;
+  let parenLevel = 0;
+
+  return tokens.map((token, index) => {
+    if (token.type === TokenType.OPEN_PAREN) {
+      parenLevel++;
+      atStatementStart = true;
+    } else if (token.type === TokenType.CLOSE_PAREN) {
+      parenLevel--;
+      atStatementStart = false;
+    } else if (token.type === TokenType.DELIMITER) {
+      atStatementStart = true;
+    }
+
+    if (atStatementStart && token.type === TokenType.RESERVED_CLAUSE && token.text === 'FROM') {
+      const hasPipe = tokens.slice(index + 1).some(next => next.type === TokenType.PIPE);
+      if (hasPipe) {
+        atStatementStart = false;
+        return { ...token, type: TokenType.PIPE_FROM };
+      }
+    }
+
+    if (token.type !== TokenType.LINE_COMMENT && token.type !== TokenType.BLOCK_COMMENT) {
+      atStatementStart = false;
+    }
